'use strict'

const { test } = require('node:test')
const boot = require('..')

test('pretty print', (t, done) => {
  t.plan(19)

  const app = boot()
  app
    .use(first)
    .use(duplicate, { count: 3 })
    .use(second).after(afterUse).after(after)
    .use(duplicate, { count: 2 })
    .use(third).after(after)
    .use(duplicate, { count: 1 })

  const linesExpected = [/^root \d+ ms$/,
    /^в”њв”Ђв”Ђ first \d+ ms$/,
    /^в”њв”Ђв”¬ duplicate \d+ ms$/,
    /^в”ЃEв””в”Ђв”¬ duplicate \d+ ms$/,
    /^в”ЃE{3}в””в”Ђв”¬ duplicate \d+ ms$/,
    /^в”ЃE{5}в””в”Ђв”Ђ duplicate \d+ ms$/,
    /^в”њв”Ђв”Ђ second \d+ ms$/,
    /^в”њв”Ђв”¬ bound _after \d+ ms$/,
    /^в”ЃEв””в”Ђв”Ђ afterInsider \d+ ms$/,
    /^в”њв”Ђв”Ђ bound _after \d+ ms$/,
    /^в”њв”Ђв”¬ duplicate \d+ ms$/,
    /^в”ЃEв””в”Ђв”¬ duplicate \d+ ms$/,
    /^в”ЃE{3}в””в”Ђв”Ђ duplicate \d+ ms$/,
    /^в”њв”Ђв”Ђ third \d+ ms$/,
    /^в”њв”Ђв”Ђ bound _after \d+ ms$/,
    /^в””в”Ђв”¬ duplicate \d+ ms$/,
    /^ {2}в””в”Ђв”Ђ duplicate \d+ ms$/,
    /^$/
  ]

  app.on('preReady', () => {
    const print = app.prettyPrint()
    const lines = print.split('\n')

    t.assert.strictEqual(lines.length, linesExpected.length)
    lines.forEach((l, i) => {
      t.assert.match(l, linesExpected[i])
    })
    done()
  })

  function first (s, opts, done) {
    done()
  }
  function second (s, opts, done) {
    done()
  }
  function third (s, opts, done) {
    done()
  }
  function after (err, cb) {
    cb(err)
  }
  function afterUse (err, cb) {
    app.use(afterInsider)
    cb(err)
  }

  function afterInsider (s, opts, done) {
    done()
  }

  function duplicate (instance, opts, cb) {
    if (opts.count > 0) {
      instance.use(duplicate, { count: opts.count - 1 })
    }
    setTimeout(cb, 20)
  }
})
